        "- * 输入包括移动方向、跳跃、攻击等动作。",
        "- */",
        "-struct PlayerInput {",
        "-    uint32_t playerId;              ///< 玩家ID",
        "-    uint32_t inputHash;             ///< 输入校验和（用于检测异常输入）",
        "-    uint32_t inputTick;             ///< 输入所属的tick",
        "-    ",
        "-    // 输入数据",
        "-    float moveX = 0.0f;             ///< 移动X轴（-1.0 ~ 1.0）",
        "-    float moveY = 0.0f;             ///< 移动Y轴（-1.0 ~ 1.0）",
