        "-",
        "-    /** @brief 反序列化 */",
        "-    bool Deserialize(const uint8_t*& data) {",
        "-        std::memcpy(&playerId, data, sizeof(uint32_t));",
        "-        data += sizeof(uint32_t);",
        "-        std::memcpy(&inputHash, data, sizeof(uint32_t));",
        "-        data += sizeof(uint32_t);",
        "-        std::memcpy(&inputTick, data, sizeof(uint32_t));",
