{"content":"/**
 * @file physics_state.h
 * @brief 物理状态定义 - 用于服务器权威物理同步的核心数据结构
 * 
 * 本文件定义了物理世界中刚体的状态信息，包括位置、旋转、速度等。
 * 这些状态信息会在服务器和客户端之间传输，用于同步物理世界。
 * 
 * 设计原则：
 * 1. 数据紧凑 - 减少网络传输带宽
 * 2. 确定性问题 - 使用固定精度浮点数
 * 3. 可扩展性 - 支持不同种类的物理对象
 */

#pragma once

#include <cstdint>
#include <cstring>
#include <vector>
#include <array>
#include <cmath>
#include <algorithm>
#include <stdexcept>

namespace PhysicsSync {

// ====================================================================
// 基础数学类型定义
// ====================================================================

/**
 * @brief 三维向量 - 用于位置、速度、力等
 * 
 * 注意：为了确保跨平台一致性，所有浮点运算应在确定性环境下进行。
 * 服务器端和客户端必须使用相同的浮点模型编译。
 */
struct Vec3 {
    float x = 0.0f;
    float y = 0.0f;
    float z = 0.0f;

    /** @brief 零向量 */
    static Vec3 Zero() { return Vec3{0.0f, 0.0f, 0.0f}; }

    /** @brief 单位向量（向上） */
    static Vec3 Up() { return Vec3{0.0f, 1.0f, 0.0f}; }

    /** @brief 向量加法 */
    Vec3 operator+(const Vec3& other) const {
        return Vec3{x + other.x, y + other.y, z + other.z};
    }

    /** @brief 向量减法 */
    Vec3 operator-(const Vec3& other) const {
        return Vec3{x - other.x, y - other.y, z - other.z};
    }

    /** @brief 向量标量乘法 */
    Vec3 operator*(float scalar) const {
        return Vec3{x * scalar, y * scalar, z * scalar};
    }

    /** @brief 向量点乘 */
    float Dot(const Vec3& other) const {
        return x * other.x + y * other.y + z * other.z;
    }

    /** @brief 向量叉乘 */
    Vec3 Cross(const Vec3& other) const {
        return Vec3{
