        "-} // namespace PhysicsSync",
        "+/**",
        "+ * @file physics_state.h",
        "+ * @brief 物理状态定义 - 用于服务器权威物理同步的核心数据结构",
        "+ * ",
        "+ * 本文件定义了物理世界中刚体的状态信息，包括位置、旋转、速度等。",
        "+ * 这些状态信息会在服务器和客户端之间传输，用于同步物理世界。",
        "+ * ",
        "+ * 设计原则：",
        "+ * 1. 数据紧凑 - 减少网络传输带宽",
        "+ * 2. 确定性问题 - 使用固定精度浮点数",
        "+ * 3. 可扩展性 - 支持不同种类的物理对象",
        "+ */",
        "+",
        "+#pragma once",
        "+",
        "+#include <cstdint>",
        "+#include <cstring>",
        "+#include <vector>",
        "+#include <array>",
        "+#include <cmath>",
        "+#include <algorithm>",
        "+#include <stdexcept>",
