        "-            reinterpret_cast<const uint8_t*>(&lookX), ",
        "-            reinterpret_cast<const uint8_t*>(&lookX) + sizeof(float));",
        "-        buffer.insert(buffer.end(), ",
        "-            reinterpret_cast<const uint8_t*>(&lookY), ",
        "-            reinterpret_cast<const uint8_t*>(&lookY) + sizeof(float));",
