        "-        std::memcpy(&lookY, data, sizeof(float));",
        "-        data += sizeof(float);",
        "-        std::memcpy(&buttons, data, sizeof(uint32_t));",
        "-        data += sizeof(uint32_t);",
        "-        return true;",
        "-    }",
        "-",
        "-    /** @brief 获取序列化后的字节大小 */",
        "-    static constexpr size_t SerializedSizeBytes() {",
        "-        return sizeof(uint32_t) * 4 + sizeof(float) * 4;",
        "-    }",
        "-};",
