{"content":"/**
 * @file physics_client.h
 * @brief 物理客户端 - 客户端预测与校正
 * 
 * 本文件定义了物理客户端的核心类，负责：
 * 1. 接收服务器的物理状态快照
 * 2. 客户端预测（基于收到的状态预测未来位置）
 * 3. 状态校正（当收到服务器权威状态时进行校正）
 * 4. 渲染插值（平滑显示远程物体）
 * 
 * 架构：客户端预测 + 服务器校正
 * - 客户端本地运行物理模拟，提供即时反馈
 * - 收到服务器快照后，校正本地状态
 * - 使用插值使远程物体运动平滑
 */

#pragma once

#include "../common/physics_state.h"
#include "../common/timestep_manager.h"
#include "../common/deterministic_random.h"
#include <memory>
#include <vector>
#include <unordered_map>
#include <deque>
#include <functional>
#include <mutex>
#include <atomic>

namespace PhysicsSync {

// =====================================================================
// 客户端状态
// =====================================================================

/**
 * @brief 客户端运行状态
 */
enum class ClientState {
    DISCONNECTED,       ///< 未连接
    CONNECTING,         ///< 连接中
    CONNECTED,          ///< 已连接
    SYNCING,            ///< 同步中
    RUNNING,            ///< 运行中
    RECONNECTING,       ///< 重连中
};

/**
 * @brief 校正模式
 */
enum class CorrectionMode {
    NONE,               ///< 无需校正
    LERP,               ///< 线性插值校正（平滑）
    SNAP,               ///< 立即校正（无平滑）
    ROLLBACK,           ///< 回滚重模拟（用于本地玩家）
};

// =====================================================================
// 渲染回调
// =====================================================================

/**
 * @brief 渲染回调函数类型
 * 
 * 当需要渲染帧时，客户端会调用此回调。
 * @param timestamp 渲染时间戳（毫秒）
 * @param interpolationAlpha 插值alpha值（0.0-1.0）
 */
typedef void (*render_callback_t)(uint32_t timestamp, float interpolationAlpha);

// =====================================================================
// 物理客户端
// =====================================================================

/**
 * @brief 物理客户端核心类
 * 
 * 负责：
 * - 与服务器的网络连接
 * - 物理状态的接收和预测
 * - 输入序列的构建和发送
 * - 渲染帧的生成
 * 
 * 线程模型：
 * - 网络线程：接收服务器数据，发送玩家输入
 * - 模拟线程：运行客户端物理模拟
 * - 渲染线程：调用渲染回调
 */
class PhysicsClient {
public:
    /**
     * @brief 构造函数
     * @param renderCallback 渲染回调函数
     */
    explicit PhysicsClient(render_callback_t renderCallback);

    /**
     * @brief 析构函数
     */
    ~PhysicsClient();

    // 禁止拷贝
    PhysicsClient(const PhysicsClient&) = delete;
    PhysicsClient& operator=(const PhysicsClient&) = delete;

    /**
     * @brief 初始化客户端
     * @return 是否成功初始化
     */
    bool Initialize();

    /**
     * @brief 连接到服务器
     * @param host 服务器地址
     * @param port 服务器端口
     * @return 是否成功
     */
    bool Connect(const std::string& host, uint16_t port);

    /**
     * @brief 断开连接
     */
    void Disconnect();

    /**
     * @brief 检查是否已连接
     * @return 如果已连接返回true
     */
    bool IsConnected() const { return state_ == ClientState::CONNECTED || 
                                       state_ == ClientState::RUNNING; }

    /**
     * @brief 获取当前状态
     * @return 客户端状态
     */
    ClientState GetState() const { return state_; }

    /**
     * @brief 发送玩家输入
     * @param input 输入数据
     * @return 是否成功发送
     */
    bool SendInput(const PlayerInput& input);

    /**
     * @brief 处理收到的服务器快照
     * @param snapshot 快照数据
     * @return 是否成功处理
     */
    bool ProcessSnapshot(const PhysicsWorldSnapshot& snapshot);

    /**
     * @brief 获取当前物理世界状态
     * @param output 输出参数
     * @return 是否有可用状态
     */
    bool GetWorldState(PhysicsWorldSnapshot& output);

    /**
     * @brief 设置校正模式
     * @param mode 校正模式
     */
    void SetCorrectionMode(CorrectionMode mode) { correctionMode_ = mode; }

    /**
     * @brief 获取校正模式
     * @return 当前校正模式
     */
    CorrectionMode GetCorrectionMode() const { return correctionMode_; }

    /**
     * @brief 获取与服务器的延迟
     * @return 延迟（毫秒）
     */
    float GetLatency() const { return latencyMs_; }

    /**
     * @brief 获取统计信息
     * @return 统计信息字符串
     */
    std::string GetStatistics() const;

    /**
     * @brief 运行主循环
     * 
     * 此函数在主线程中运行，负责：
     * - 处理网络I/O
     * - 更新物理模拟
     * - 调用渲染回调
     */
    void Run();

    /**
     * @brief 停止客户端
     */
    void Stop();

private:
    /**
     * @brief 网络线程函数
     */
    void NetworkThread();

    /**
     * @brief 模拟线程函数
     */
    void SimulationThread();

    /**
     * @brief 应用服务器快照到本地状态
     * @param snapshot 服务器快照
     */
    void ApplySnapshot(const PhysicsWorldSnapshot& snapshot);

    /**
     * @brief 执行客户端预测
     * @param deltaTime 时间增量
     */
    void Predict(float deltaTime);

    /**
     * @brief 校正本地状态
     * @param targetSnapshot 目标快照
     */
    void CorrectState(const PhysicsWorldSnapshot& targetSnapshot);

    /**
     * @brief 构建待发送的输入
     * @return 输入队列
     */
    std::vector<PlayerInput> BuildInputQueue();

    /**
     * @brief 计算平滑校正量
     * @param from 起始状态
     * @param to 目标状态
     * @param alpha 插值因子
     * @return 校正后的状态
     */
    PhysicsObjectState LerpState(const PhysicsObjectState& from,
                                  const PhysicsObjectState& to,
                                  float alpha);

    // 配置参数
    float snapshotInterval_;        ///< 快照间隔（秒）
    float predictionWindow_;        ///< 预测窗口（秒）

    // 时间管理
    TimeStepManager timeManager_;   ///< 时间步长管理器

    // 渲染
    render_callback_t renderCallback_;  ///< 渲染回调

    // 网络
    std::string serverHost_;        ///< 服务器地址
    uint16_t serverPort_;           ///< 服务器端口
    std::unique_ptr<std::thread> networkThread_;
    std::unique_ptr<std::thread> simulationThread_;

    // 状态管理
    ClientState state_;             ///< 客户端状态
    CorrectionMode correctionMode_; ///< 校正模式

    // 本地物理世界
    PhysicsWorldSnapshot localSnapshot_;  ///< 本地快照（用于渲染）
    PhysicsWorldSnapshot predictedSnapshot_; ///< 预测快照
    PhysicsWorldSnapshot serverSnapshot_;  ///< 最后收到的服务器快照

    // 输入管理
    std::vector<PlayerInput> inputQueue_;
    std::mutex inputMutex_;
    uint32_t nextInputTick_;
    uint32_t lastConfirmedTick_;

    // 网络统计
    float latencyMs_;                 ///< 往返延迟（毫秒）
    uint32_t packetsReceived_;        ///< 接收的包数
    uint32_t packetsSent_;            ///< 发送的包数
    uint32_t corrections_;            ///< 校正次数
    uint32_t predictionHits_;         ///< 预测命中次数

    // 控制标志
