{"content":"/**
 * @file client_main.cpp
 * @brief 客户端主程序入口
 * 
 * 启动物理客户端，连接到服务器，运行物理模拟和渲染循环。
 */

#include "physics_client.h"
#include "../common/physics_state.h"
#include "../common/timestep_manager.h"
#include <iostream>
#include <thread>
#include <signal.h>

namespace PhysicsSync {

// 全局客户端指针（用于信号处理）
PhysicsClient* g_client = nullptr;

/**
 * @brief 信号处理函数
 */
void SignalHandler(int signal) {
    if (g_client && g_client->IsConnected()) {
        std::cout << "\n[Main] Received signal " << signal 
                  << ", shutting down..." << std::endl;
        g_client->Disconnect();
    }
}

/**
 * @brief 模拟渲染回调
 * 
 * 实际项目中这里会调用Filament或其他渲染引擎
 */
void MockRenderCallback(uint32_t timestamp, float interpolationAlpha) {
    static int frameCount = 0;
    frameCount++;

    // 每100帧打印一次
    if (frameCount % 100 == 0) {
        std::cout << "[Render] Frame " << frameCount 
                  << " (tick: " << timestamp 
                  << ", alpha: " << interpolationAlpha << ")" << std::endl;
    }
}

/**
 * @brief 打印使用说明
 */
void PrintUsage(const char* programName) {
    std::cout << "Usage: " << programName 
              << " [options]" << std::endl
              << "Options:" << std::endl
              << "  --server <host>   Server address (default: localhost)" << std::endl
              << "  --port <n>        Server port (default: 7777)" << std::endl
              << "  --help            Show this help message" << std::endl;
}

} // namespace PhysicsSync

int main(int argc, char* argv[]) {
    using namespace PhysicsSync;

    // 设置信号处理
    signal(SIGINT, SignalHandler);
    signal(SIGTERM, SignalHandler);

    // 解析命令行参数
    std::string serverHost = "localhost";
    uint16_t port = 7777;

    for (int i = 1; i < argc; i++) {
        if (strcmp(argv[i], "--server") == 0 && i + 1 < argc) {
            serverHost = argv[++i];
        } else if (strcmp(argv[i], "--port") == 0 && i + 1 < argc) {
            port = static_cast<uint16_t>(std::atoi(argv[++i]));
        } else if (strcmp(argv[i], "--help") == 0) {
            PrintUsage(argv[0]);
            return 0;
        }
    }

    std::cout << "============================================" << std::endl;
    std::cout << "   PhysicsSync Client" << std::endl;
    std::cout << "============================================" << std::endl;
    std::cout << "  Server: " << serverHost << std::endl;
    std::cout << "  Port: " << port << std::endl;
    std::cout << "============================================" << std::endl;

    // 创建客户端
    PhysicsClient client(MockRenderCallback);

    if (!client.Initialize()) {
        std::cerr << "Failed to initialize client!" << std::endl;
        return 1;
    }

    g_client = &client;

    // 连接到服务器
    if (!client.Connect(serverHost, port)) {
        std::cerr << "Failed to connect to server!" << std::endl;
        return 1;
    }

    std::cout << "\n[Main] Client is running. Press Ctrl+C to stop." << std::endl;
    std::cout << "[Main] Note: This is a demo client without Filament rendering." << std::endl;

    // 模拟一些输入
    std::thread inputThread([&client]() {
        PlayerInput input(1, 0);
        int tick = 0;

        while (client.IsConnected()) {
            // 模拟移动输入（正弦波）
            input.moveX = std::sin(tick * 0.1f) * 0.5f;
            input.moveY = 0.0f;
            input.lookX = 0.0f;
            input.lookY = 0.0f;
            input.inputTick = static_cast<uint32_t>(tick);
            input.ComputeHash();

            client.SendInput(input);

            tick++;
            std::this_thread::sleep_for(std::chrono::milliseconds(16));  // ~60Hz
        }
    });

    // 运行主循环
    client.Run();

    // 等待输入线程结束
    if (inputThread.joinable()) {
        inputThread.join();
    }

    g_client = nullptr;

    std::cout << "\n[Main] Client statistics:" << std::endl;
    std::cout << client.GetStatistics() << std::endl;

    std::cout << "\n[Main] Client stopped." << std::endl;
    return 0;
}
