{"content":"/**
 * @file kcp_wrapper.cpp
 * @brief KCP协议封装实现
 * 
 * 本文件提供KCP协议的C++封装实现。
 * 注意：这是一个简化实现，实际项目中需要链接真正的KCP库。
 */

#include "kcp_wrapper.h"
#include <cstring>
#include <iostream>

namespace PhysicsSync {

// =====================================================================
// KCPWrapper 实现
// =====================================================================

KCPWrapper::KCPWrapper(uint32_t conv, IKCPOutput* output)
    : kcp_(nullptr)
    , output_(output)
    , initialized_(false)
{
    // 注意：实际项目中这里会调用IKCPOutput::CreateKCP()创建KCP实例
    // 简化实现：仅设置基本成员
    (void)conv;

    std::cout << "[KCPWrapper] Initialized (mock implementation)" << std::endl;
    initialized_ = true;
}

KCPWrapper::~KCPWrapper() {
    // 注意：实际项目中需要释放KCP实例
    kcp_ = nullptr;
    output_ = nullptr;
    initialized_ = false;
}

void KCPWrapper::SetConfig(const KCPConfig& config) {
    if (!initialized_) {
        std::cerr << "[KCPWrapper] Not initialized!" << std::endl;
        return;
    }

    // 注意：实际项目中会调用IKCPOutput::SetKCPParam()
    (void)config;

    std::cout << "[KCPWrapper] Config set: conv=" << config.conv 
              << ", nodelay=" << config.nodelay << std::endl;
}

void KCPWrapper::Update(uint32_t currentTick) {
    if (!initialized_) {
        return;
    }

    // 注意：实际项目中会调用IKCPOutput::UpdateKCP()
    (void)currentTick;
}

int KCPWrapper::Send(const void* data, int size) {
    if (!initialized_ || !output_ || size <= 0) {
        return -1;
    }

    // 注意：实际项目中会调用IKCPOutput::IKCPSend()
    // 这里简单模拟发送成功
    (void)data;
    (void)size;

    return 0;
}

int KCPWrapper::Recv(void* buffer, int size) {
    if (!initialized_ || !buffer || size <= 0) {
        return 0;
    }

    // 注意：实际项目中会调用IKCPOutput::IKCPRecv()
    // 简化实现：返回0（没有数据）
    (void)buffer;
    (void)size;

    return 0;
}

void KCPWrapper::Input(const void* data, int size) {
    if (!initialized_ || !data || size <= 0) {
        return;
    }

    // 注意：实际项目中会调用IKCPOutput::Input()
    (void)data;
    (void)size;
}

bool KCPWrapper::CanSend() const {
    if (!initialized_) {
        return false;
    }

    // 简化实现：总是返回true
    return true;
}

int KCPWrapper::SendQueueSize() const {
    if (!initialized_) {
        return 0;
    }

    // 简化实现：返回0
    return 0;
}

int KCPWrapper::RecvQueueSize() const {
    if (!initialized_) {
        return 0;
    }

    // 简化实现：返回0
    return 0;
}

void KCPWrapper::Reset() {
    // 注意：实际项目中会重置KCP状态
    std::cout << "[KCPWrapper] Reset" << std::endl;
}

int KCPWrapper::GetRTT() const {
    if (!initialized_) {
        return -1;
    }

    // 简化实现：返回0
    return 0;
}

int KCPWrapper::GetCwnd() const {
    if (!initialized_) {
        return 0;
    }

    // 简化实现：返回默认值
    return 30;
}

} // namespace PhysicsSync
